import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import type { AuthState, Trader, User } from '@/types/models';
import { authApi } from '@/services/api';

interface AuthContextType extends AuthState {
  /** True once initial auth check (getProfile) has completed. Used by ProtectedRoute to avoid redirecting before bootstrap. */
  hasBootstrapped: boolean;
  login: (email: string, password: string) => Promise<void>;
  register: (data: any) => Promise<void>;
  logout: () => void;
  isLoading: boolean;
  error: string | null;
  clearError: () => void;
}

const AuthContext = createContext<AuthContextType>({
  isAuthenticated: false,
  user: null,
  trader: null,
  hasBootstrapped: false,
  login: async () => {},
  register: async () => {},
  logout: () => {},
  isLoading: false,
  error: null,
  clearError: () => {},
});

export const useAuth = () => useContext(AuthContext);

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [state, setState] = useState<AuthState>({
    isAuthenticated: false,
    user: null,
    trader: null,
  });
  const [hasBootstrapped, setHasBootstrapped] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    let cancelled = false;
    const bootstrap = async () => {
      try {
        let profile = await authApi.getProfile();
        // Retry once on 401 to avoid redirecting when session cookie is valid but first request was transient (e.g. race)
        if (!cancelled && !profile) {
          await new Promise((r) => setTimeout(r, 400));
          if (!cancelled) profile = await authApi.getProfile();
        }
        if (!cancelled && profile) {
          setState({
            isAuthenticated: true,
            user: profile.user,
            trader: profile.trader,
          });
        }
      } catch {
        // ignore bootstrap errors; user will be treated as logged out
      } finally {
        if (!cancelled) {
          setHasBootstrapped(true);
        }
      }
    };
    bootstrap();
    return () => {
      cancelled = true;
    };
  }, []);

  const login = useCallback(async (email: string, password: string) => {
    setIsLoading(true);
    setError(null);
    try {
      const result = await authApi.login(email, password);
      setState({
        isAuthenticated: true,
        user: result.user,
        trader: result.trader,
      });
    } catch (e: any) {
      setError(e.message || 'Login failed');
      throw e;
    } finally {
      setIsLoading(false);
    }
  }, []);

  const register = useCallback(async (data: any) => {
    setIsLoading(true);
    setError(null);
    try {
      const result = await authApi.register({
        business_name: data.businessName || data.business_name || '',
        owner_name: data.ownerName || data.owner_name || '',
        mobile: data.mobile || '',
        email: data.email || '',
        password: data.password || '',
        address: data.address || '',
        city: data.city || '',
        state: data.state || '',
        pin_code: data.pinCode || data.pin_code || '',
        category: data.categoryName || data.category || '',
      });
      setState({
        isAuthenticated: true,
        user: result.user,
        trader: result.trader,
      });
    } catch (e: any) {
      setError(e.message || 'Registration failed');
      throw e;
    } finally {
      setIsLoading(false);
    }
  }, []);

  const logout = useCallback(() => {
    setState({ isAuthenticated: false, user: null, trader: null });
  }, []);

  const clearError = useCallback(() => setError(null), []);

  return (
    <AuthContext.Provider value={{ ...state, hasBootstrapped, login, register, logout, isLoading, error, clearError }}>
      {children}
    </AuthContext.Provider>
  );
};

import React, { createContext, useContext, useState, useCallback } from 'react';

type FontSizeLevel = 0 | 1 | 2;
const LABELS: Record<FontSizeLevel, string> = { 0: 'Default', 1: 'Large', 2: 'Extra Large' };
const SCALE: Record<FontSizeLevel, number> = { 0: 1, 1: 1.15, 2: 1.3 };

type FontSizeContextType = {
  level: FontSizeLevel;
  scale: number;
  label: string;
  decrease: () => void;
  reset: () => void;
  increase: () => void;
};

const FontSizeContext = createContext<FontSizeContextType>({
  level: 0, scale: 1, label: 'Default',
  decrease: () => {}, reset: () => {}, increase: () => {},
});

export const useFontSize = () => useContext(FontSizeContext);

export const FontSizeProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [level, setLevel] = useState<FontSizeLevel>(() => {
    const saved = localStorage.getItem('mercotrace-font-size');
    return (saved !== null && [0, 1, 2].includes(Number(saved))) ? Number(saved) as FontSizeLevel : 0;
  });

  const persist = (l: FontSizeLevel) => {
    setLevel(l);
    localStorage.setItem('mercotrace-font-size', String(l));
  };

  const decrease = useCallback(() => persist(Math.max(0, level - 1) as FontSizeLevel), [level]);
  const reset = useCallback(() => persist(0), []);
  const increase = useCallback(() => persist(Math.min(2, level + 1) as FontSizeLevel), [level]);

  return (
    <FontSizeContext.Provider value={{ level, scale: SCALE[level], label: LABELS[level], decrease, reset, increase }}>
      {children}
    </FontSizeContext.Provider>
  );
};

import React, { createContext, useContext, useEffect, useState } from 'react';

type ThemeContextType = {
  isDark: boolean;
  toggleTheme: () => void;
};

const ThemeContext = createContext<ThemeContextType>({ isDark: false, toggleTheme: () => {} });

export const useTheme = () => useContext(ThemeContext);

export const ThemeProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [isDark, setIsDark] = useState(() => {
    const saved = localStorage.getItem('aeroglass-theme');
    return saved === 'dark';
  });

  useEffect(() => {
    document.documentElement.classList.toggle('dark', isDark);
    localStorage.setItem('aeroglass-theme', isDark ? 'dark' : 'light');
  }, [isDark]);

  const toggleTheme = () => setIsDark(prev => !prev);

  return (
    <ThemeContext.Provider value={{ isDark, toggleTheme }}>
      {children}
    </ThemeContext.Provider>
  );
};

