          return [b.billNumber, b.billingName || b.buyerMark, String(bags), String(b.grandTotal ?? 0), String(comm), String(uf), String(b.buyerCoolie ?? 0), '0', '0', String(b.pendingBalance ?? b.grandTotal ?? 0)];
        });
