import { useNavigate } from 'react-router-dom';
import { cn } from '@/lib/utils';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import BottomNav from '@/components/BottomNav';
import { useDesktopMode } from '@/hooks/use-desktop';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from '@/components/ui/dialog';
import { contactApi, stockPurchaseApi, commodityApi } from '@/services/api';
import type { Contact, Commodity } from '@/types/models';
import type { StockPurchaseDTO } from '@/services/api';
import { toast } from 'sonner';

interface PurchaseLineItem {
  id: string;
  commodityId: string;
  quantity: number;
  rate: number;
  amount: number;
}

interface PurchaseCharge {
  id: string;
  name: string;
  amount: number;
}

const StockPurchasePage = () => {
  const navigate = useNavigate();
  const isDesktop = useDesktopMode();
  const [vendors, setVendors] = useState<Contact[]>([]);
  const [records, setRecords] = useState<StockPurchaseDTO[]>([]);
  const [totalElements, setTotalElements] = useState(0);
  const [totalPages, setTotalPages] = useState(0);
  const [currentPage, setCurrentPage] = useState(0);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [showForm, setShowForm] = useState(false);
  const [search, setSearch] = useState('');
  const [vendorsLoading, setVendorsLoading] = useState(false);
  const [commodities, setCommodities] = useState<Commodity[]>([]);
  const [commoditiesLoading, setCommoditiesLoading] = useState(false);

  // Form state
  const [selectedVendor, setSelectedVendor] = useState<Contact | null>(null);
  const [vendorSearch, setVendorSearch] = useState('');
  const [items, setItems] = useState<PurchaseLineItem[]>([{ id: crypto.randomUUID(), commodityId: '', quantity: 0, rate: 0, amount: 0 }]);
  const [charges, setCharges] = useState<PurchaseCharge[]>([]);
  const [saving, setSaving] = useState(false);

  const pageSize = 10;

  const loadPurchases = (page: number = 0) => {
    setLoading(true);
    setError(null);
    stockPurchaseApi
      .getPage({ page, size: pageSize, vendorSearch: search.trim() || undefined })
      .then((p) => {
        setRecords(p.content);
        setTotalElements(p.totalElements);
        setTotalPages(p.totalPages);
        setCurrentPage(p.number);
      })
      .catch((e) => {
        setError(e instanceof Error ? e.message : 'Failed to load purchases');
        setRecords([]);
      })
      .finally(() => setLoading(false));
  };

  useEffect(() => {
    if (!showForm) return;
    setVendorsLoading(true);
    contactApi
      .list()
      .then(c => setVendors(c.filter(v => v.type === 'SELLER')))
      .catch(() => setVendors([]))
      .finally(() => setVendorsLoading(false));
  }, [showForm]);

  useEffect(() => {
    if (!showForm) return;
    setCommoditiesLoading(true);
    commodityApi
      .list()
      .then(setCommodities)
      .catch(() => setCommodities([]))
      .finally(() => setCommoditiesLoading(false));
  }, [showForm]);

  useEffect(() => {
    loadPurchases(0);
  }, [search]);

  const filteredVendors = useMemo(() => {
    if (!vendorSearch) return vendors;
    const q = vendorSearch.toLowerCase();
    return vendors.filter(v => v.name?.toLowerCase().includes(q) || v.phone?.includes(q));
  }, [vendors, vendorSearch]);

  const subtotal = useMemo(() => items.reduce((s, i) => s + i.amount, 0), [items]);
  const totalCharges = useMemo(() => charges.reduce((s, c) => s + c.amount, 0), [charges]);
  const grandTotal = subtotal + totalCharges;
  const pageTotalSpent = useMemo(() => records.reduce((s, r) => s + (r.grandTotal ?? 0), 0), [records]);

  const updateItem = (id: string, field: string, value: any) => {
    setItems(prev => prev.map(i => {
      if (i.id !== id) return i;
      const updated = { ...i, [field]: value };
      updated.amount = updated.quantity * updated.rate;
      return updated;
    }));
  };

  const addItem = () => setItems(prev => [...prev, { id: crypto.randomUUID(), commodityId: '', quantity: 0, rate: 0, amount: 0 }]);
  const removeItem = (id: string) => setItems(prev => prev.filter(i => i.id !== id));
  const addCharge = () => setCharges(prev => [...prev, { id: crypto.randomUUID(), name: '', amount: 0 }]);
  const removeCharge = (id: string) => setCharges(prev => prev.filter(c => c.id !== id));

  const handleSave = () => {
    if (!selectedVendor || items.every(i => i.amount === 0)) {
      toast.error('Select vendor and add at least one item');
      return;
    }
    const validItems = items.filter(i => i.amount > 0);
    const missingCommodity = validItems.find(i => !i.commodityId || String(i.commodityId).trim() === '');
    if (missingCommodity) {
      toast.error('Select a commodity for every line item');
      return;
    }
    const vendorId = Number(selectedVendor.contact_id);
    if (!Number.isFinite(vendorId)) {
      toast.error('Invalid vendor');
      return;
    }
    setSaving(true);
    stockPurchaseApi
      .create({
        vendorId,
        items: validItems.map((i) => {
          const commodity = commodities.find(c => String(c.commodity_id) === String(i.commodityId));
          return {
            commodityId: Number(i.commodityId),
            commodity: commodity?.commodity_name,
            quantity: i.quantity,
            rate: i.rate,
            amount: i.amount,
          };
        }),
        charges: charges.map((c) => ({ name: c.name, amount: c.amount })),
      })
      .then(() => {
        setShowForm(false);
        resetForm();
        loadPurchases(0);
        toast.success('Stock purchase recorded & inventory updated');
      })
      .catch((e) => {
        toast.error(e instanceof Error ? e.message : 'Failed to save purchase');
      })
      .finally(() => setSaving(false));
  };

  const resetForm = () => {
    setSelectedVendor(null);
    setVendorSearch('');
    setItems([{ id: crypto.randomUUID(), commodityId: '', quantity: 0, rate: 0, amount: 0 }]);
    setCharges([]);
  };

  const displayRecords = records;

  return (
    <div className="min-h-[100dvh] bg-background pb-28 lg:pb-6">
      {!isDesktop && (
        <div className="bg-gradient-to-br from-teal-400 via-emerald-500 to-green-600 pt-[max(1.5rem,env(safe-area-inset-top))] pb-6 px-4 rounded-b-[2rem] relative overflow-hidden">
          <div className="absolute inset-0 bg-[radial-gradient(circle_at_70%_20%,rgba(255,255,255,0.2)_0%,transparent_50%)]" />
          <div className="absolute top-2 right-2 opacity-10">
            <ShoppingCart className="w-28 h-28 text-white" />
          </div>
          <div className="relative z-10">
            <div className="flex items-center gap-3 mb-4">
              <button onClick={() => navigate('/home')} className="w-10 h-10 rounded-full bg-white/20 backdrop-blur-md flex items-center justify-center active:scale-95 transition-transform">
                <ArrowLeft className="w-5 h-5 text-white" />
              </button>
              <div className="flex-1">
                <h1 className="text-xl font-bold text-white flex items-center gap-2">
                  <Box className="w-5 h-5" /> Stock Purchase
                </h1>
                <p className="text-white/80 text-xs font-medium">Record vendor stock purchases</p>
              </div>
              <button onClick={() => setShowForm(true)} className="w-10 h-10 rounded-full bg-white/25 backdrop-blur-md flex items-center justify-center active:scale-95 transition-transform">
                <Plus className="w-5 h-5 text-white" />
              </button>
            </div>

            {/* Quick Stats */}
            <div className="grid grid-cols-2 gap-2">
              <div className="bg-white/20 backdrop-blur-md rounded-xl px-3 py-2">
                <p className="text-white/70 text-[10px] font-semibold uppercase tracking-wider">Purchases</p>
                <p className="text-white text-lg font-bold">{loading ? '…' : totalElements}</p>
              </div>
              <div className="bg-white/20 backdrop-blur-md rounded-xl px-3 py-2">
                <p className="text-white/70 text-[10px] font-semibold uppercase tracking-wider">Page Total</p>
                <p className="text-white text-lg font-bold">₹{(loading ? 0 : pageTotalSpent).toLocaleString()}</p>
              </div>
            </div>
          </div>
        </div>
      )}

      {isDesktop && (
        <div className="px-8 pt-6 pb-4 flex items-center gap-4">
          <div className="relative flex-1 max-w-md">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
            <Input placeholder="Search purchases by vendor…" value={search} onChange={e => setSearch(e.target.value)} className="pl-10 h-11" />
          </div>
          <div className="flex items-center gap-3">
            <div className="glass-card rounded-xl px-4 py-2 flex items-center gap-2">
              <Package className="w-4 h-4 text-teal-500" />
              <span className="text-sm font-semibold">{loading ? '…' : totalElements} purchases</span>
            </div>
            <div className="glass-card rounded-xl px-4 py-2 flex items-center gap-2">
              <TrendingUp className="w-4 h-4 text-emerald-500" />
              <span className="text-sm font-semibold">₹{(loading ? 0 : pageTotalSpent).toLocaleString()} (page)</span>
            </div>
          </div>
          <Button onClick={() => setShowForm(true)} className="bg-gradient-to-r from-teal-500 to-emerald-500 hover:from-teal-600 hover:to-emerald-600 text-white font-bold h-11">
            <Plus className="w-4 h-4 mr-1.5" /> New Purchase
          </Button>
        </div>
      )}

      <div className={cn("px-4", isDesktop ? "lg:px-8" : "mt-4")}>
        <div className="flex items-center gap-2 mb-3">
          <div className="w-1.5 h-5 rounded-full bg-gradient-to-b from-teal-400 to-emerald-500" />
          <h2 className="text-sm font-bold text-foreground uppercase tracking-wide">Purchase History</h2>
        </div>

        {error ? (
          <div className="glass-card rounded-2xl p-6 text-center">
            <p className="text-sm font-semibold text-destructive mb-1">Error loading purchases</p>
            <p className="text-xs text-muted-foreground">{error}</p>
          </div>
        ) : loading ? (
          <div className="glass-card rounded-2xl p-10 text-center">
            <p className="text-sm text-muted-foreground">Loading purchases…</p>
          </div>
        ) : displayRecords.length === 0 ? (
          <div className="glass-card rounded-2xl p-10 text-center">
            <div className="w-16 h-16 rounded-2xl bg-teal-100 dark:bg-teal-900/20 mx-auto mb-4 flex items-center justify-center">
              <Box className="w-8 h-8 text-teal-500" />
            </div>
            <p className="text-sm font-semibold text-foreground mb-1">No Stock Purchases Yet</p>
            <p className="text-xs text-muted-foreground">Tap + to record your first vendor purchase</p>
          </div>
        ) : isDesktop ? (
          <div className="glass-card rounded-2xl overflow-hidden">
            <table className="w-full text-sm">
              <thead>
                <tr className="bg-gradient-to-r from-teal-50 to-emerald-50 dark:from-teal-900/10 dark:to-emerald-900/10 border-b border-border/50">
                  <th className="text-left p-3 text-teal-800 dark:text-teal-300 font-semibold text-xs uppercase tracking-wide">Date</th>
                  <th className="text-left p-3 text-teal-800 dark:text-teal-300 font-semibold text-xs uppercase tracking-wide">Vendor</th>
                  <th className="text-right p-3 text-teal-800 dark:text-teal-300 font-semibold text-xs uppercase tracking-wide">Items</th>
                  <th className="text-right p-3 text-teal-800 dark:text-teal-300 font-semibold text-xs uppercase tracking-wide">Subtotal</th>
                  <th className="text-right p-3 text-teal-800 dark:text-teal-300 font-semibold text-xs uppercase tracking-wide">Charges</th>
                  <th className="text-right p-3 text-teal-800 dark:text-teal-300 font-semibold text-xs uppercase tracking-wide">Grand Total</th>
                  <th className="text-left p-3 text-teal-800 dark:text-teal-300 font-semibold text-xs uppercase tracking-wide">Lot #</th>
                </tr>
              </thead>
              <tbody>
                {displayRecords.map(r => (
                  <tr key={r.id} className="border-b border-border/30 last:border-0 hover:bg-teal-50/30 dark:hover:bg-teal-900/5 transition-colors">
                    <td className="p-3 text-muted-foreground">{r.createdAt ? new Date(r.createdAt).toLocaleDateString() : '—'}</td>
                    <td className="p-3 font-semibold">{r.vendorName}</td>
                    <td className="p-3 text-right">{r.items?.length ?? 0}</td>
                    <td className="p-3 text-right">₹{(r.subtotal ?? 0).toLocaleString()}</td>
                    <td className="p-3 text-right text-amber-600 dark:text-amber-400">₹{(r.totalCharges ?? 0).toLocaleString()}</td>
                    <td className="p-3 text-right font-bold text-emerald-600 dark:text-emerald-400">₹{(r.grandTotal ?? 0).toLocaleString()}</td>
                    <td className="p-3 text-xs text-muted-foreground max-w-[200px] truncate">{(r.lotNumbers ?? []).join(', ') || '—'}</td>
                  </tr>
                ))}
              </tbody>
            </table>
            {totalPages > 1 && (
              <div className="flex justify-center gap-2 py-3 border-t border-border/30">
                <Button variant="outline" size="sm" disabled={currentPage <= 0} onClick={() => loadPurchases(currentPage - 1)}>Previous</Button>
                <span className="text-xs self-center px-2">Page {currentPage + 1} of {totalPages}</span>
                <Button variant="outline" size="sm" disabled={currentPage >= totalPages - 1} onClick={() => loadPurchases(currentPage + 1)}>Next</Button>
              </div>
            )}
          </div>
        ) : (
          <div className="space-y-3">
            {displayRecords.map(r => (
              <motion.div key={r.id} initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }}
                className="glass-card rounded-xl p-4 border-l-4 border-l-teal-400">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-2">
                    <div className="w-9 h-9 rounded-lg bg-gradient-to-br from-teal-400 to-emerald-500 flex items-center justify-center">
                      <User className="w-4 h-4 text-white" />
                    </div>
                    <div>
                      <p className="font-bold text-sm">{r.vendorName}</p>
                      <p className="text-[11px] text-muted-foreground">{(r.items?.length ?? 0)} items · {r.createdAt ? new Date(r.createdAt).toLocaleDateString() : '—'}</p>
                    </div>
                  </div>
                  <span className="font-black text-emerald-600 dark:text-emerald-400">₹{(r.grandTotal ?? 0).toLocaleString()}</span>
                </div>
                <div className="mt-2.5 flex flex-wrap gap-1">
                  {(r.lotNumbers ?? []).map((ln, i) => (
                    <span key={i} className="px-2 py-0.5 rounded-full bg-teal-100 dark:bg-teal-900/30 text-teal-700 dark:text-teal-300 text-[10px] font-bold">{ln}</span>
                  ))}
                </div>
              </motion.div>
            ))}
            {totalPages > 1 && (
              <div className="flex justify-center gap-2 pt-2">
                <Button variant="outline" size="sm" disabled={currentPage <= 0} onClick={() => loadPurchases(currentPage - 1)}>Previous</Button>
                <span className="text-xs self-center">Page {currentPage + 1} of {totalPages}</span>
                <Button variant="outline" size="sm" disabled={currentPage >= totalPages - 1} onClick={() => loadPurchases(currentPage + 1)}>Next</Button>
              </div>
            )}
          </div>
        )}
      </div>

      {/* Purchase Form Dialog */}
      <Dialog open={showForm} onOpenChange={setShowForm}>
        <DialogContent className={cn("sm:max-w-2xl max-h-[85vh] overflow-y-auto", isDesktop && "glass-card")}>
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-teal-400 to-emerald-500 flex items-center justify-center">
                <Box className="w-4 h-4 text-white" />
              </div>
              New Stock Purchase
            </DialogTitle>
            <DialogDescription>Record purchase from vendor with cost allocation</DialogDescription>
          </DialogHeader>

          <div className="space-y-4 py-2">
            {/* Vendor Selection */}
            <div>
              <label className="text-xs font-bold text-teal-700 dark:text-teal-400 mb-1.5 block uppercase tracking-wide">Vendor</label>
              {selectedVendor ? (
                <div className="rounded-xl p-3 flex items-center justify-between bg-teal-50 dark:bg-teal-900/20 border border-teal-200 dark:border-teal-800/50">
                  <div className="flex items-center gap-2">
                    <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-teal-400 to-emerald-500 flex items-center justify-center">
                      <User className="w-4 h-4 text-white" />
                    </div>
                    <span className="font-bold text-sm">{selectedVendor.name}</span>
                    <span className="text-xs text-muted-foreground">{selectedVendor.phone}</span>
                  </div>
                  <Button variant="ghost" size="sm" onClick={() => setSelectedVendor(null)}>Change</Button>
                </div>
              ) : (
                <div>
                  <Input placeholder="Search vendor by name or phone…" value={vendorSearch} onChange={e => setVendorSearch(e.target.value)} className="h-11" disabled={vendorsLoading} />
                  {vendorsLoading && (
                    <p className="mt-1.5 text-xs text-muted-foreground">Loading vendors…</p>
                  )}
                  {!vendorsLoading && vendorSearch && (
                    <div className="mt-1 max-h-32 overflow-y-auto border border-border rounded-xl bg-background">
                      {filteredVendors.map(v => (
                        <button key={v.contact_id} onClick={() => { setSelectedVendor(v); setVendorSearch(''); }}
                          className="w-full text-left px-3 py-2.5 hover:bg-teal-50 dark:hover:bg-teal-900/10 text-sm font-medium transition-colors">{v.name} · {v.phone}</button>
                      ))}
                      {filteredVendors.length === 0 && <p className="px-3 py-2 text-xs text-muted-foreground">No vendors found</p>}
                    </div>
                  )}
                </div>
              )}
            </div>

            {/* Line Items */}
            <div>
              <div className="flex items-center justify-between mb-2">
                <label className="text-xs font-bold text-teal-700 dark:text-teal-400 uppercase tracking-wide">Line Items</label>
                <Button variant="ghost" size="sm" onClick={addItem} className="text-teal-600"><Plus className="w-3 h-3 mr-1" /> Add Item</Button>
              </div>
              <div className="space-y-2">
                {items.map((item, idx) => (
                  <div key={item.id} className="rounded-xl p-3 bg-muted/30 border border-border/50">
                    <div className="flex items-center gap-1 mb-2">
                      <span className="w-6 h-6 rounded-full bg-teal-100 dark:bg-teal-900/30 text-teal-700 dark:text-teal-300 flex items-center justify-center text-[10px] font-bold">{idx + 1}</span>
                      <span className="text-xs text-muted-foreground font-medium flex-1">Item {idx + 1}</span>
                      {items.length > 1 && (
                        <button onClick={() => removeItem(item.id)} className="text-destructive p-1 hover:bg-destructive/10 rounded"><Trash2 className="w-3.5 h-3.5" /></button>
                      )}
                    </div>
                    <div className="grid grid-cols-12 gap-2 items-center">
                      <div className="col-span-5">
                        <label className="sr-only">Commodity</label>
                        <select
                          value={item.commodityId}
                          onChange={e => updateItem(item.id, 'commodityId', e.target.value)}
                          className="h-9 w-full rounded-md border border-input bg-background px-3 py-1.5 text-xs"
                          disabled={commoditiesLoading}
                        >
                          <option value="">{commoditiesLoading ? 'Loading…' : 'Select commodity'}</option>
                          {commodities.map((c) => (
                            <option key={c.commodity_id} value={c.commodity_id}>{c.commodity_name}</option>
                          ))}
                          {!commoditiesLoading && commodities.length === 0 && <option value="" disabled>No commodities</option>}
                        </select>
                      </div>
                      <div className="col-span-2">
                        <Input type="number" placeholder="Qty" value={item.quantity || ''} onChange={e => updateItem(item.id, 'quantity', parseInt(e.target.value) || 0)} className="text-xs h-9" />
                      </div>
                      <div className="col-span-3">
                        <Input type="number" placeholder="Rate ₹" value={item.rate || ''} onChange={e => updateItem(item.id, 'rate', parseFloat(e.target.value) || 0)} className="text-xs h-9" />
                      </div>
                      <div className="col-span-2 text-right">
                        <span className="text-sm font-bold text-emerald-600 dark:text-emerald-400">₹{item.amount.toLocaleString()}</span>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {/* Charges */}
            <div>
              <div className="flex items-center justify-between mb-2">
                <label className="text-xs font-bold text-amber-700 dark:text-amber-400 uppercase tracking-wide">Overhead Charges</label>
                <Button variant="ghost" size="sm" onClick={addCharge} className="text-amber-600"><Plus className="w-3 h-3 mr-1" /> Add Charge</Button>
              </div>
              {charges.length === 0 && (
                <p className="text-xs text-muted-foreground bg-muted/30 rounded-lg px-3 py-2">No charges added. Freight, labour etc. will be allocated proportionally to items.</p>
              )}
              {charges.map(ch => (
                <div key={ch.id} className="flex gap-2 mb-2 items-center">
                  <Input placeholder="e.g. Freight, Labour" value={ch.name} onChange={e => setCharges(prev => prev.map(c => c.id === ch.id ? { ...c, name: e.target.value } : c))} className="flex-1 h-9 text-xs" />
                  <Input type="number" placeholder="₹ Amount" value={ch.amount || ''} onChange={e => setCharges(prev => prev.map(c => c.id === ch.id ? { ...c, amount: parseFloat(e.target.value) || 0 } : c))} className="w-28 h-9 text-xs" />
                  <button onClick={() => removeCharge(ch.id)} className="text-destructive p-1 hover:bg-destructive/10 rounded"><Trash2 className="w-3.5 h-3.5" /></button>
                </div>
              ))}
            </div>

            {/* Summary */}
            <div className="rounded-xl p-4 bg-gradient-to-r from-teal-50 to-emerald-50 dark:from-teal-900/20 dark:to-emerald-900/20 border border-teal-200 dark:border-teal-800/50 space-y-2">
              <div className="flex justify-between text-sm"><span className="text-muted-foreground font-medium">Subtotal</span><span className="font-semibold">₹{subtotal.toLocaleString()}</span></div>
              <div className="flex justify-between text-sm"><span className="text-amber-600 dark:text-amber-400 font-medium">+ Charges</span><span className="font-semibold text-amber-600 dark:text-amber-400">₹{totalCharges.toLocaleString()}</span></div>
              <div className="flex justify-between text-base font-black border-t border-teal-200 dark:border-teal-800/50 pt-2 mt-1">
                <span>Grand Total</span><span className="text-emerald-600 dark:text-emerald-400 text-xl">₹{grandTotal.toLocaleString()}</span>
              </div>
            </div>
          </div>

          <div className="flex gap-2 pt-2">
            <Button variant="outline" onClick={() => setShowForm(false)} className="flex-1 h-11" disabled={saving}>Cancel</Button>
            <Button onClick={handleSave} className="flex-1 h-11 bg-gradient-to-r from-teal-500 to-emerald-500 hover:from-teal-600 hover:to-emerald-600 text-white font-bold shadow-lg" disabled={saving}>
              <Save className="w-4 h-4 mr-1.5" /> {saving ? 'Saving…' : 'Save Purchase'}
            </Button>
          </div>
        </DialogContent>
      </Dialog>

      <BottomNav />
    </div>
  );
};

export default StockPurchasePage;

import { useState, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { ArrowLeft, MapPin, Loader2, ChevronDown, Store, FileText, Navigation, Hash, Sun, Moon, Save, Building, Map, AlignLeft } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { MercotraceIcon } from '@/components/MercotraceLogo';
import { useTheme } from '@/context/ThemeContext';
import { useAuth } from '@/context/AuthContext';
import { cn } from '@/lib/utils';
import { toast } from 'sonner';
import loginBg from '@/assets/login-bg.jpg';

const BUSINESS_CATEGORIES = ['Retailer', 'Exporter', 'Trader', 'Commission Agent', 'Distributor', 'Wholesaler'];
const STATES = ['Karnataka'];
const GSTIN_REGEX = /^[0-9]{2}[A-Z]{5}[0-9]{4}[A-Z]{1}[1-9A-Z]{1}Z[0-9A-Z]{1}$/;

// Deterministic particles (same pattern as login/register)
const PARTICLES = Array.from({ length: 10 }, (_, i) => ({
  id: i,
  left: `${10 + (i * 8.3) % 85}%`,
  top: `${5 + (i * 13.7) % 85}%`,
  delay: (i * 0.4) % 2,
}));

interface FormData {
  businessName: string;
  businessCategory: string;
  gstin: string;
  address: string;
  shopNo: string;
  state: string;
  market: string;
  description: string;
}

const TraderSetupPage = () => {
  const navigate = useNavigate();
  const { isDark, toggleTheme } = useTheme();
  const { register, isLoading } = useAuth();

  const [form, setForm] = useState<FormData>({
    businessName: '', businessCategory: '', gstin: '', address: '',
    shopNo: '', state: 'Karnataka', market: '', description: '',
  });
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [touched, setTouched] = useState<Record<string, boolean>>({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isFetchingLocation, setIsFetchingLocation] = useState(false);
  const [showCategoryDropdown, setShowCategoryDropdown] = useState(false);
  const [showStateDropdown, setShowStateDropdown] = useState(false);

  const inputClass = "pl-12 h-12 sm:h-14 text-base rounded-xl bg-white/90 border-0 text-blue-900 placeholder:text-blue-400";
  const inputClassPlain = "h-12 sm:h-14 text-base rounded-xl bg-white/90 border-0 text-blue-900 placeholder:text-blue-400";

  const updateField = (field: keyof FormData, value: string) => {
    setForm(prev => ({ ...prev, [field]: value }));
    if (errors[field]) setErrors(prev => { const n = { ...prev }; delete n[field]; return n; });
  };

  const handleBlur = (field: string) => {
    setTouched(prev => ({ ...prev, [field]: true }));
    validateField(field);
  };

  const validateField = (field: string): string => {
    let error = '';
    switch (field) {
      case 'businessName': if (!form.businessName.trim()) error = 'This field is required'; break;
      case 'businessCategory': if (!form.businessCategory) error = 'Please select a category'; break;
      case 'gstin': if (form.gstin && !GSTIN_REGEX.test(form.gstin.toUpperCase())) error = 'Invalid GSTIN format'; break;
      case 'address': if (!form.address.trim()) error = 'This field is required'; break;
      case 'shopNo': if (!form.shopNo.trim()) error = 'This field is required'; break;
      case 'state': if (!form.state) error = 'This field is required'; break;
      case 'market': if (!form.market.trim()) error = 'This field is required'; break;
    }
    setErrors(prev => error ? { ...prev, [field]: error } : (() => { const n = { ...prev }; delete n[field]; return n; })());
    return error;
  };

  const validateAll = (): boolean => {
    const fields = ['businessName', 'businessCategory', 'address', 'shopNo', 'state', 'market', 'gstin'];
    let valid = true;
    fields.forEach(f => { if (validateField(f)) valid = false; });
    setTouched(fields.reduce((a, f) => ({ ...a, [f]: true }), {}));
    return valid;
  };

  const handleUseCurrentLocation = useCallback(async () => {
    if (!navigator.geolocation) { toast.error('Geolocation not supported'); return; }
    setIsFetchingLocation(true);
    try {
      const pos = await new Promise<GeolocationPosition>((resolve, reject) => {
        navigator.geolocation.getCurrentPosition(resolve, reject, { enableHighAccuracy: true, timeout: 10000, maximumAge: 0 });
      });
      const { latitude, longitude } = pos.coords;
      const res = await fetch(`https://nominatim.openstreetmap.org/reverse?lat=${latitude}&lon=${longitude}&format=json&addressdetails=1`);
      if (!res.ok) throw new Error('Location fetch failure');
      const data = await res.json();
      updateField('address', data.display_name || `${latitude}, ${longitude}`);
      toast.success('Location fetched successfully');
    } catch (err: any) {
      if (err?.code === 1) toast.error('Location permission denied');
      else if (err?.code === 3) toast.error('Location request timed out');
      else toast.error('Could not fetch location. Enter manually.');
    } finally { setIsFetchingLocation(false); }
  }, []);

  const handleSubmit = async () => {
    if (!validateAll()) { toast.error('Please fill all required fields'); return; }
    setIsSubmitting(true);
    try {
      await register({
        businessName: form.businessName.trim(), ownerName: form.businessName.trim(),
        mobile: '', email: `trader_${Date.now()}@mercotrace.app`, password: 'trader123456',
        address: form.address.trim(), city: form.market.trim(), state: form.state, pinCode: '', category: form.businessCategory,
      });
      toast.success('Trader profile saved successfully!');
      navigate('/home', { replace: true });
    } catch { toast.error('Failed to save profile. Please try again.'); }
    finally { setIsSubmitting(false); }
  };

  const FieldError = ({ field }: { field: string }) => {
    if (!touched[field] || !errors[field]) return null;
    return <motion.p initial={{ opacity: 0, y: -4 }} animate={{ opacity: 1, y: 0 }} className="text-xs text-red-200 mt-1 ml-1" role="alert">{errors[field]}</motion.p>;
  };

  return (
    <div className="h-[100dvh] relative overflow-hidden flex flex-col">
      {/* Background — identical to login/register */}
      <img src={loginBg} alt="" className="absolute inset-0 w-full h-full object-cover z-0" fetchPriority="high" decoding="async" width={1920} height={1080} />
      <div className="absolute inset-0 bg-gradient-to-br from-blue-900/75 via-blue-800/65 to-violet-900/75 z-[1]" />
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_30%_20%,rgba(255,255,255,0.15)_0%,transparent_50%)] z-[1]" />
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_70%_80%,rgba(123,97,255,0.2)_0%,transparent_40%)] z-[1]" />

      {/* Particles */}
      <div className="absolute inset-0 overflow-hidden pointer-events-none z-[2]" aria-hidden="true">
        {PARTICLES.map(p => (
          <motion.div key={p.id} className="absolute w-1.5 h-1.5 bg-white/25 rounded-full"
            style={{ left: p.left, top: p.top }}
            animate={{ y: [-15, 15], opacity: [0.15, 0.5, 0.15] }}
            transition={{ duration: 4, repeat: Infinity, delay: p.delay }}
          />
        ))}
      </div>

      {/* Content */}
      <div className="relative z-10 flex-1 flex flex-col min-h-0">
        {/* Top bar */}
        <div className="flex items-center justify-between px-5 pt-[max(1rem,env(safe-area-inset-top))]">
          <button onClick={() => navigate('/login')} className="w-11 h-11 rounded-2xl bg-white/20 backdrop-blur-md flex items-center justify-center text-white border border-white/20" aria-label="Go back">
            <ArrowLeft className="w-5 h-5" />
          </button>
          <button onClick={toggleTheme} className="w-11 h-11 rounded-2xl bg-white/20 backdrop-blur-md flex items-center justify-center text-white border border-white/20" aria-label={isDark ? 'Switch to light mode' : 'Switch to dark mode'}>
            {isDark ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
          </button>
        </div>

        {/* Scrollable form area */}
        <div className="flex-1 flex flex-col items-center overflow-y-auto px-6 py-4 no-scrollbar">
          {/* Logo */}
          <motion.div initial={{ scale: 0 }} animate={{ scale: 1 }} transition={{ type: 'spring', damping: 15 }} className="relative mb-4">
            <div className="w-16 h-16 rounded-2xl bg-white/15 backdrop-blur-md flex items-center justify-center shadow-2xl border border-white/20">
              <MercotraceIcon size={32} color="white" className="drop-shadow-lg" />
            </div>
          </motion.div>

          <h1 className="text-2xl font-bold text-white mb-1 drop-shadow-lg">Trader Setup</h1>
          <p className="text-white/70 text-sm mb-5">Set up your business profile to get started</p>

          {/* Form */}
          <motion.div initial={{ opacity: 0, y: 30 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.2 }} className="w-full max-w-sm space-y-3 pb-28">

            {/* Section: Business Details */}
            <p className="text-xs font-semibold text-white/50 uppercase tracking-wider pt-1 flex items-center gap-1.5">
              <Store className="w-3.5 h-3.5" /> Business Details
            </p>

            {/* Business Name */}
            <div>
              <div className="relative">
                <Building className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-blue-800/50" />
                <Input placeholder="Business Name *" value={form.businessName} onChange={e => updateField('businessName', e.target.value)} onBlur={() => handleBlur('businessName')}
                  className={cn(inputClass, touched.businessName && errors.businessName && "ring-2 ring-red-400/50")} maxLength={100} />
              </div>
              <FieldError field="businessName" />
            </div>

            {/* Business Category Dropdown */}
            <div className="relative">
              <button type="button"
                onClick={() => { setShowCategoryDropdown(!showCategoryDropdown); setShowStateDropdown(false); }}
                onBlur={() => setTimeout(() => { setShowCategoryDropdown(false); handleBlur('businessCategory'); }, 150)}
                className={cn("w-full h-12 sm:h-14 px-4 rounded-xl bg-white/90 text-sm flex items-center justify-between",
                  form.businessCategory ? 'text-blue-900' : 'text-blue-400',
                  touched.businessCategory && errors.businessCategory && "ring-2 ring-red-400/50"
                )}>
                <span>{form.businessCategory || 'Select Business Category *'}</span>
                <ChevronDown className={cn('w-4 h-4 text-blue-800/50 transition-transform', showCategoryDropdown && 'rotate-180')} />
              </button>
              {showCategoryDropdown && (
                <motion.div initial={{ opacity: 0, y: -8 }} animate={{ opacity: 1, y: 0 }}
                  className="absolute z-50 top-full mt-2 w-full rounded-2xl py-2 max-h-48 overflow-auto bg-white/95 backdrop-blur-xl shadow-xl border border-white/50">
                  {BUSINESS_CATEGORIES.map(cat => (
                    <button key={cat} type="button" onMouseDown={e => e.preventDefault()}
                      onClick={() => { updateField('businessCategory', cat); setShowCategoryDropdown(false); }}
                      className={cn("w-full text-left px-4 py-2.5 text-sm text-blue-900 hover:bg-blue-50 transition-colors",
                        form.businessCategory === cat && "bg-blue-50 font-medium"
                      )}>{cat}</button>
                  ))}
                </motion.div>
              )}
              <FieldError field="businessCategory" />
            </div>

            {/* GSTIN */}
            <div>
              <div className="relative">
                <FileText className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-blue-800/50" />
                <Input placeholder="GSTIN (optional)" value={form.gstin} onChange={e => updateField('gstin', e.target.value.toUpperCase())} onBlur={() => handleBlur('gstin')}
                  className={cn(inputClass, "uppercase", touched.gstin && errors.gstin && "ring-2 ring-red-400/50")} maxLength={15} />
              </div>
              <FieldError field="gstin" />
            </div>

            {/* Section: Address & Location */}
            <p className="text-xs font-semibold text-white/50 uppercase tracking-wider pt-3 flex items-center gap-1.5">
              <MapPin className="w-3.5 h-3.5" /> Address & Location
            </p>

            {/* Address */}
            <div>
              <div className="relative">
                <MapPin className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-blue-800/50" />
                <Input placeholder="Search or enter address *" value={form.address} onChange={e => updateField('address', e.target.value)} onBlur={() => handleBlur('address')}
                  className={cn(inputClass, touched.address && errors.address && "ring-2 ring-red-400/50")} />
              </div>
              <FieldError field="address" />
              <button type="button" onClick={handleUseCurrentLocation} disabled={isFetchingLocation}
                className="mt-1.5 flex items-center gap-2 text-sm text-white/80 font-medium hover:text-white transition-colors min-h-[44px] px-1">
                {isFetchingLocation ? <Loader2 className="w-4 h-4 animate-spin" /> : <Navigation className="w-4 h-4" />}
                {isFetchingLocation ? 'Fetching location...' : '📍 Use my current location as address'}
              </button>
            </div>

            {/* Shop No */}
            <div>
              <div className="relative">
                <Hash className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-blue-800/50" />
                <Input placeholder="Shop No *" value={form.shopNo} onChange={e => updateField('shopNo', e.target.value)} onBlur={() => handleBlur('shopNo')}
                  className={cn(inputClass, touched.shopNo && errors.shopNo && "ring-2 ring-red-400/50")} maxLength={20} />
              </div>
              <FieldError field="shopNo" />
            </div>

            {/* Section: Market Location */}
            <p className="text-xs font-semibold text-white/50 uppercase tracking-wider pt-3 flex items-center gap-1.5">
              <Map className="w-3.5 h-3.5" /> Your Market Location
            </p>

            {/* State Dropdown */}
            <div className="relative">
              <button type="button"
                onClick={() => { setShowStateDropdown(!showStateDropdown); setShowCategoryDropdown(false); }}
                onBlur={() => setTimeout(() => { setShowStateDropdown(false); handleBlur('state'); }, 150)}
                className={cn("w-full h-12 sm:h-14 px-4 rounded-xl bg-white/90 text-sm flex items-center justify-between text-blue-900")}>
                <span>{form.state || 'Select State *'}</span>
                <ChevronDown className={cn('w-4 h-4 text-blue-800/50 transition-transform', showStateDropdown && 'rotate-180')} />
              </button>
              {showStateDropdown && (
                <motion.div initial={{ opacity: 0, y: -8 }} animate={{ opacity: 1, y: 0 }}
                  className="absolute z-50 top-full mt-2 w-full rounded-2xl py-2 bg-white/95 backdrop-blur-xl shadow-xl border border-white/50">
                  {STATES.map(s => (
                    <button key={s} type="button" onMouseDown={e => e.preventDefault()}
                      onClick={() => { updateField('state', s); setShowStateDropdown(false); }}
                      className={cn("w-full text-left px-4 py-2.5 text-sm text-blue-900 hover:bg-blue-50 transition-colors",
                        form.state === s && "bg-blue-50 font-medium"
                      )}>{s}</button>
                  ))}
                </motion.div>
              )}
              <FieldError field="state" />
            </div>

            {/* Market */}
            <div>
              <div className="relative">
                <Store className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-blue-800/50" />
                <Input placeholder="Market Name *" value={form.market} onChange={e => updateField('market', e.target.value)} onBlur={() => handleBlur('market')}
                  className={cn(inputClass, touched.market && errors.market && "ring-2 ring-red-400/50")} maxLength={100} />
              </div>
              <FieldError field="market" />
            </div>

            {/* Section: Description */}
            <p className="text-xs font-semibold text-white/50 uppercase tracking-wider pt-3 flex items-center gap-1.5">
              <AlignLeft className="w-3.5 h-3.5" /> Additional Info
            </p>

            <textarea
              placeholder="Tell us about your shop... (optional)"
              value={form.description}
              onChange={e => updateField('description', e.target.value)}
              className="w-full min-h-[100px] px-4 py-3 rounded-xl bg-white/90 border-0 text-sm text-blue-900 placeholder:text-blue-400 resize-none focus:outline-none focus:ring-2 focus:ring-white/50"
              maxLength={500}
            />

            {/* Submit button */}
            <Button onClick={handleSubmit} disabled={isSubmitting || isLoading}
              className="w-full h-12 sm:h-14 rounded-xl text-base sm:text-lg font-semibold bg-white text-blue-600 hover:bg-white/90 shadow-xl disabled:opacity-70 mt-2">
              {isSubmitting ? (
                <motion.div className="w-5 h-5 border-2 border-blue-600 border-t-transparent rounded-full" animate={{ rotate: 360 }} transition={{ duration: 1, repeat: Infinity, ease: 'linear' }} />
              ) : (
                <><Save className="w-5 h-5 mr-2" /> Save & Continue</>
              )}
            </Button>
          </motion.div>
        </div>
      </div>
    </div>
  );
};

export default TraderSetupPage;

import { useState, useEffect, useMemo, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
  ArrowLeft, Scale, Bluetooth, PenLine, Plus, Trash2,
  AlertTriangle, Search, Package, Hash, ChevronDown, Download,
  FileText, Printer
} from 'lucide-react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { useDesktopMode } from '@/hooks/use-desktop';
import { cn } from '@/lib/utils';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import BottomNav from '@/components/BottomNav';
import { toast } from 'sonner';
import { useAuctionResults } from '@/hooks/useAuctionResults';
import { commodityApi, weighingApi, printLogApi, arrivalsApi } from '@/services/api';
import type { FullCommodityConfigDto } from '@/services/api/commodities';
import type { ArrivalDetail } from '@/services/api/arrivals';

/** REQ-WGH-004: Government deduction from API full-config */
function getGovtDeductionFromConfigs(weight: number, fullConfigs: FullCommodityConfigDto[]): number {
  const withGovt = fullConfigs.find(f => f.config?.govtDeductionEnabled);
  if (withGovt && (withGovt.deductionRules?.length ?? 0) > 0) {
    const rule = withGovt.deductionRules!.find(r => weight >= r.minWeight && weight <= r.maxWeight);
    if (rule) return rule.deductionValue;
  }
  if (weight >= 1 && weight <= 35) return 1.5;
  return 0;
}

// ── Types ─────────────────────────────────────────────────
interface BidForWeighing {
  bidNumber: number;
  buyerMark: string;
  buyerName: string;
  quantity: number;
  rate: number;
  lotId: string;
  lotName: string;
  sellerName: string;
}

interface BagWeightEntry {
  bagNumber: number;
  weight: number;
  timestamp: string;
}

interface WeighingSessionData {
  sessionId: string;
  bidNumber: number;
  bagWeights: BagWeightEntry[];
  originalWeight: number;   // REQ-WGH-001: raw machine data
  deductions: number;
  netWeight: number;         // REQ-WGH-001: business billable
  manualEntry: boolean;      // REQ-WGH-002
  isComplete: boolean;
  govtDeductionApplied: boolean;
  roundOffApplied: boolean;
}

const WeighingPage = () => {
  const navigate = useNavigate();
  const isDesktop = useDesktopMode();
  const [searchParams] = useSearchParams();
  const [bids, setBids] = useState<BidForWeighing[]>([]);
  const [selectedBid, setSelectedBid] = useState<BidForWeighing | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [scaleConnected, setScaleConnected] = useState(false);

  // Weighing session
  const [session, setSession] = useState<WeighingSessionData | null>(null);
  const [currentWeight, setCurrentWeight] = useState('');
  const [manualMode, setManualMode] = useState(false);
  const [govtDeductionEnabled, setGovtDeductionEnabled] = useState(true);
  const [roundOffEnabled, setRoundOffEnabled] = useState(false);

  // REQ-WGH-008: Post-weighing slip
  const [showSlip, setShowSlip] = useState(false);
  const [completedSession, setCompletedSession] = useState<WeighingSessionData | null>(null);

  // REQ-WGH-005: Mutual exclusivity
  useEffect(() => {
    if (roundOffEnabled) setGovtDeductionEnabled(false);
  }, [roundOffEnabled]);
  useEffect(() => {
    if (govtDeductionEnabled) setRoundOffEnabled(false);
  }, [govtDeductionEnabled]);

  const { auctionResults: auctionData } = useAuctionResults();
  const [fullConfigs, setFullConfigs] = useState<FullCommodityConfigDto[]>([]);
  const [weighingSessionsList, setWeighingSessionsList] = useState<any[]>([]);
  const [arrivalDetails, setArrivalDetails] = useState<ArrivalDetail[]>([]);

  useEffect(() => {
    commodityApi.getAllFullConfigs().then(setFullConfigs);
  }, []);

  useEffect(() => {
    weighingApi.list({ page: 0, size: 2000 }).then(setWeighingSessionsList).catch(() => setWeighingSessionsList([]));
  }, []);

  // Arrivals from API (no localStorage). Load detail list for bid enrichment (lotId → lotName, sellerName).
  useEffect(() => {
    arrivalsApi
      .listDetail(0, 500)
      .then(setArrivalDetails)
      .catch(() => setArrivalDetails([]));
  }, []);

  // Load bids from auction results; enrich seller/lot names from arrival details (API).
  useEffect(() => {
    const allBids: BidForWeighing[] = [];

    auctionData.forEach((auction: any) => {
      (auction.entries || []).forEach((entry: any) => {
        let sellerName = auction.sellerName || 'Unknown';
        let lotName = auction.lotName || '';
        arrivalDetails.forEach((arr: ArrivalDetail) => {
          (arr.sellers || []).forEach((seller) => {
            (seller.lots || []).forEach((lot) => {
              if (String(lot.id) === String(auction.lotId)) {
                sellerName = seller.sellerName;
                lotName = lot.lotName || lotName;
              }
            });
          });
        });
        allBids.push({
          bidNumber: entry.bidNumber,
          buyerMark: entry.buyerMark,
          buyerName: entry.buyerName,
          quantity: entry.quantity,
          rate: entry.rate,
          lotId: String(auction.lotId),
          lotName,
          sellerName,
        });
      });
    });
    setBids(allBids);

    // PATH 1: Auto-select bid if coming from Sales Pad with ?bid=X
    const bidParam = searchParams.get('bid');
    if (bidParam && allBids.length > 0) {
      const bidNum = parseInt(bidParam);
      const found = allBids.find(b => b.bidNumber === bidNum);
      if (found) startSession(found);
    }
  }, [auctionData, arrivalDetails, searchParams]);

  const filteredBids = useMemo(() => {
    if (!searchQuery) return bids;
    const q = searchQuery.toLowerCase();
    return bids.filter(b =>
      b.buyerMark.toLowerCase().includes(q) ||
      b.buyerName.toLowerCase().includes(q) ||
      b.sellerName.toLowerCase().includes(q) ||
      String(b.bidNumber).includes(q)
    );
  }, [bids, searchQuery]);

  const startSession = (bid: BidForWeighing) => {
    setSelectedBid(bid);
    setSession({
      sessionId: crypto.randomUUID(),
      bidNumber: bid.bidNumber,
      bagWeights: [],
      originalWeight: 0,
      deductions: 0,
      netWeight: 0,
      manualEntry: false,
      isComplete: false,
      govtDeductionApplied: false,
      roundOffApplied: false,
    });
  };

  // REQ-WGH-007: Record individual bag weight
  const recordBagWeight = () => {
    const w = parseFloat(currentWeight);
    if (!w || w <= 0 || !session) return;

    // REQ-WGH-009: Min/Max alarm
    if (w < 5) toast.warning(`⚠️ Low weight: ${w}kg — verify reading`);
    if (w > 100) toast.warning(`⚠️ High weight: ${w}kg — verify reading`);

    const newBag: BagWeightEntry = {
      bagNumber: session.bagWeights.length + 1,
      weight: w,
      timestamp: new Date().toISOString(),
    };

    const updatedBags = [...session.bagWeights, newBag];
    recalcWeights(updatedBags);
    setCurrentWeight('');
  };

  // Centralized weight recalculation
  const recalcWeights = useCallback((bags: BagWeightEntry[]) => {
    const totalOriginal = bags.reduce((s, b) => s + b.weight, 0);
    // REQ-WGH-002: If manual, OW = 0
    const origWeight = manualMode ? 0 : totalOriginal;
    // REQ-WGH-004: Govt deductions per bag
    let deductions = 0;
    if (govtDeductionEnabled) {
      deductions = bags.reduce((s, b) => s + getGovtDeductionFromConfigs(b.weight, fullConfigs), 0);
    }
    // REQ-WGH-003: NW = OW - D (use totalOriginal for calc even if manual)
    let netWeight = totalOriginal - deductions;
    // REQ-WGH-005: Round-off on FINAL value only
    if (roundOffEnabled) {
      netWeight = Math.round(netWeight);
    }
    setSession(prev => prev ? {
      ...prev,
      bagWeights: bags,
      originalWeight: origWeight,
      deductions,
      netWeight,
      manualEntry: manualMode,
      govtDeductionApplied: govtDeductionEnabled,
      roundOffApplied: roundOffEnabled,
    } : prev);
  }, [manualMode, govtDeductionEnabled, roundOffEnabled]);

  // REQ-WGH-006: Average weight logic
  const applyAverageWeight = () => {
    if (!session || session.bagWeights.length === 0 || !selectedBid) return;
    const totalSampleWeight = session.bagWeights.reduce((s, b) => s + b.weight, 0);
    const n = session.bagWeights.length;
    const avgWeight = totalSampleWeight / n; // AW = ΣWi ÷ n
    const totalEstWeight = avgWeight * selectedBid.quantity; // TEW = AW × Q

    let deductions = 0;
    if (govtDeductionEnabled) {
      deductions = getGovtDeductionFromConfigs(avgWeight, fullConfigs) * selectedBid.quantity;
    }

    let netWeight = totalEstWeight - deductions;
    if (roundOffEnabled) netWeight = Math.round(netWeight);

    setSession(prev => prev ? {
      ...prev,
      originalWeight: manualMode ? 0 : totalEstWeight,
      deductions,
      netWeight,
    } : prev);

    toast.success(
      `AW = ${avgWeight.toFixed(2)}kg (${n} samples) × ${selectedBid.quantity} bags = TEW ${totalEstWeight.toFixed(2)}kg`
    );
  };

  // Complete session and save (backend only; no localStorage for business data)
  const completeSession = async () => {
    if (!session || !selectedBid) return;

    const payload = {
      session_id: session.sessionId,
      lot_id: Number(selectedBid.lotId) || 0,
      bid_number: session.bidNumber,
      buyer_mark: selectedBid.buyerMark,
      buyer_name: selectedBid.buyerName,
      seller_name: selectedBid.sellerName,
      lot_name: selectedBid.lotName,
      total_bags: selectedBid.quantity,
      original_weight: session.originalWeight,
      net_weight: session.netWeight,
      manual_entry: session.manualEntry,
      bag_weights: session.bagWeights.map(b => ({ bagNumber: b.bagNumber, weight: b.weight, timestamp: b.timestamp })),
      deductions: session.deductions,
      govt_deduction_applied: session.govtDeductionApplied,
      round_off_applied: session.roundOffApplied,
    };

    try {
      await weighingApi.create(payload);
      setWeighingSessionsList(prev => [...prev, {
        session_id: session.sessionId,
        lot_id: selectedBid.lotId,
        bid_number: session.bidNumber,
        buyer_mark: selectedBid.buyerMark,
        buyer_name: selectedBid.buyerName,
        seller_name: selectedBid.sellerName,
        lot_name: selectedBid.lotName,
        total_bags: selectedBid.quantity,
        original_weight: session.originalWeight,
        net_weight: session.netWeight,
        manual_entry: session.manualEntry,
        bag_weights: session.bagWeights,
        deductions: session.deductions,
        govt_deduction_applied: session.govtDeductionApplied,
        round_off_applied: session.roundOffApplied,
        created_at: new Date().toISOString(),
      }]);
    } catch {
      toast.error('Failed to save weighing session');
      return;
    }

    setCompletedSession({ ...session });
    setShowSlip(true);

    toast.success(`Weighing complete! Net: ${session.netWeight.toFixed(2)}kg`);
    setSession(null);
    setSelectedBid(null);
  };

  const removeBag = (bagNumber: number) => {
    if (!session) return;
    const updatedBags = session.bagWeights.filter(b => b.bagNumber !== bagNumber)
      .map((b, i) => ({ ...b, bagNumber: i + 1 }));
    recalcWeights(updatedBags);
  };

  // ═══ REQ-WGH-008: POST-WEIGHING SLIP (Thermal printout) ═══
  if (showSlip && completedSession) {
    const totalWeight = completedSession.bagWeights.reduce((s, b) => s + b.weight, 0);
    return (
      <div className="min-h-[100dvh] bg-gradient-to-b from-background via-background to-blue-50/30 dark:to-blue-950/10 pb-28 lg:pb-6">
        {!isDesktop ? (
        <div className="bg-gradient-to-br from-slate-600 via-slate-700 to-slate-800 pt-[max(1.5rem,env(safe-area-inset-top))] pb-5 px-4 rounded-b-[2rem]">
          <div className="relative z-10 flex items-center gap-3">
            <button onClick={() => setShowSlip(false)}
              aria-label="Go back" className="w-10 h-10 rounded-full bg-white/20 backdrop-blur flex items-center justify-center">
              <ArrowLeft className="w-5 h-5 text-white" />
            </button>
            <div>
              <h1 className="text-lg font-bold text-white flex items-center gap-2">
                <FileText className="w-5 h-5" /> Post-Weighing Slip
              </h1>
              <p className="text-white/70 text-xs">REQ-WGH-008 · Thermal Format</p>
            </div>
          </div>
        </div>
        ) : (
        <div className="px-8 py-5 flex items-center gap-4">
          <Button onClick={() => setShowSlip(false)} variant="outline" size="sm" className="rounded-xl h-9">
            <ArrowLeft className="w-4 h-4 mr-1.5" /> Back
          </Button>
          <div>
            <h2 className="text-lg font-bold text-foreground flex items-center gap-2">
              <FileText className="w-5 h-5 text-slate-500" /> Post-Weighing Slip
            </h2>
            <p className="text-sm text-muted-foreground">REQ-WGH-008 · Thermal Format</p>
          </div>
        </div>
        )}

        <div className="px-4 mt-4">
          {/* Thermal receipt style */}
          <div className="bg-card border border-border rounded-xl p-4 font-mono text-xs space-y-2 shadow-lg">
            <div className="text-center border-b border-dashed border-border pb-2">
              <p className="font-bold text-sm text-foreground">MERCOTRACE</p>
              <p className="text-muted-foreground">Weighing Slip</p>
              <p className="text-muted-foreground">{new Date().toLocaleDateString()} {new Date().toLocaleTimeString()}</p>
            </div>

            <div className="border-b border-dashed border-border pb-2 space-y-1">
              <div className="flex justify-between"><span className="text-muted-foreground">Bid #</span><span className="font-bold text-foreground">{completedSession.bidNumber}</span></div>
              <div className="flex justify-between"><span className="text-muted-foreground">Mode</span><span className="font-bold text-foreground">{completedSession.manualEntry ? 'MANUAL' : 'DIGITAL SCALE'}</span></div>
              {completedSession.govtDeductionApplied && <div className="flex justify-between"><span className="text-muted-foreground">Govt Ded.</span><span className="font-bold text-foreground">APPLIED</span></div>}
              {completedSession.roundOffApplied && <div className="flex justify-between"><span className="text-muted-foreground">Round Off</span><span className="font-bold text-foreground">APPLIED</span></div>}
            </div>

            {/* Individual bag weights */}
            <div className="border-b border-dashed border-border pb-2">
              <p className="font-bold text-foreground mb-1">BAG WEIGHTS ({completedSession.bagWeights.length})</p>
              <div className="grid grid-cols-4 gap-x-1 gap-y-0.5">
                {completedSession.bagWeights.map(bag => (
                  <div key={bag.bagNumber} className="text-right text-foreground">
                    <span className="text-muted-foreground mr-1">{bag.bagNumber}.</span>{bag.weight.toFixed(1)}
                  </div>
                ))}
              </div>
            </div>

            {/* Summary */}
            <div className="space-y-1 pt-1">
              <div className="flex justify-between"><span className="text-muted-foreground">Total Weight</span><span className="font-bold text-foreground">{totalWeight.toFixed(2)} kg</span></div>
              <div className="flex justify-between"><span className="text-muted-foreground">Original Wt (Legal)</span><span className="font-bold text-foreground">{completedSession.originalWeight.toFixed(2)} kg</span></div>
              <div className="flex justify-between"><span className="text-muted-foreground">Deductions</span><span className="font-bold text-destructive">−{completedSession.deductions.toFixed(2)} kg</span></div>
              <div className="flex justify-between border-t border-dashed border-border pt-1 text-sm">
                <span className="font-bold text-foreground">NET WEIGHT</span>
                <span className="font-black text-lg text-emerald-600 dark:text-emerald-400">{completedSession.netWeight.toFixed(2)} kg</span>
              </div>
            </div>

            {/* Formulas */}
            <div className="text-center text-muted-foreground/70 text-[9px] border-t border-dashed border-border pt-2 space-y-0.5">
              <p>NW = OW − D</p>
              {completedSession.bagWeights.length > 0 && (
                <p>AW = Σ Wi ÷ n = {(totalWeight / completedSession.bagWeights.length).toFixed(2)} kg</p>
              )}
              {completedSession.manualEntry && <p>⚠ Manual Entry: OW = 0 (no scale used)</p>}
            </div>

            <div className="text-center border-t border-dashed border-border pt-2">
              <p className="text-muted-foreground">--- END OF SLIP ---</p>
            </div>
          </div>

          <div className="flex gap-3 mt-4">
            <Button onClick={async () => {
              const printedAt = new Date().toISOString();
              try {
                await printLogApi.create({
                  reference_type: 'WEIGHING_SLIP',
                  reference_id: completedSession.sessionId,
                  print_type: 'WEIGHING_SLIP',
                  printed_at: printedAt,
                });
              } catch {
                // backend optional
              }
              toast.success('Weighing slip sent to printer!');
            }}
