        </div>
        {!isDesktop && <BottomNav />}
      </div>
    );
  }

  // ═══ BID LIST FOR WEIGHING ═══
  return (
    <div className="min-h-[100dvh] bg-gradient-to-b from-background via-background to-blue-50/30 dark:to-blue-950/10 pb-28 lg:pb-6">
