      {!isDesktop && (
        <div className="bg-gradient-to-br from-orange-400 via-amber-500 to-yellow-500 pt-[max(1.5rem,env(safe-area-inset-top))] pb-6 px-4 rounded-b-[2rem] relative overflow-hidden">
