      )}

      <div className="px-4 mt-4 space-y-2">
        {filteredBids.length === 0 ? (
          <div className="glass-card rounded-2xl p-8 text-center">
            <Scale className="w-10 h-10 text-muted-foreground/30 mx-auto mb-3" />
